import SwiftUI
import AIUsagesTrackersLib

/// Displays a time-window metric: name, gauge bar with theoretical marker,
/// percentage, remaining time, and next reset date.
struct TimeWindowMetricRow: View {
    let name: String
    let resetAt: ISODate
    let windowDuration: DurationMinutes
    let usagePercent: UsagePercent

    private var actualFraction: Double {
        Double(usagePercent.rawValue) / 100.0
    }

    var body: some View {
        let now = Date()
        let theoretical = theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
        let tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: theoretical)
            .map(consumptionTier(ratio:))

        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(name)
                    .font(.system(size: 11, weight: .medium))
                    .foregroundStyle(.secondary)
                Spacer()
                Text("\(usagePercent.rawValue)%")
                    .font(.system(size: 11, weight: .semibold).monospacedDigit())
            }

            GaugeBar(
                actual: actualFraction,
                theoretical: theoretical,
                tier: tier
            )

            HStack {
                Text(formatRemainingTime(resetAt: resetAt, now: now))
                    .font(.system(size: 10).monospacedDigit())
                    .foregroundStyle(.secondary)
                Spacer()
                Text("resets \(formatResetDate(resetAt, now: now))")
                    .font(.system(size: 10))
                    .foregroundStyle(.secondary)
            }
        }
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// A horizontal progress bar with an actual fill and a theoretical consumption marker.
/// The theoretical marker is a thin vertical tick showing expected consumption based on elapsed time.
struct GaugeBar: View {
    let actual: Double
    let theoretical: Double
    var tier: ConsumptionTier?

    private static let barHeight: CGFloat = 6
    private static let markerWidth: CGFloat = 2.5
    private static let cornerRadius: CGFloat = 3

    var body: some View {
        GeometryReader { geo in
            let width = geo.size.width

            ZStack(alignment: .leading) {
                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(.quaternary)

                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(fillColor)
                    .frame(width: width * clamp(actual))

                // Skip marker when no window data — avoids a tick pinned to the left edge at 0.
                if theoretical > 0 {
                    RoundedRectangle(cornerRadius: Self.markerWidth / 2)
                        .fill(.primary)
                        .frame(width: Self.markerWidth, height: Self.barHeight + 4)
                        .offset(x: width * clamp(theoretical) - Self.markerWidth / 2)
                }
            }
        }
        .frame(height: Self.barHeight)
    }

    private var fillColor: Color {
        if let tier { return tier.color }
        return .accentColor
    }

    private func clamp(_ value: Double) -> CGFloat {
        CGFloat(min(max(value, 0), 1))
    }
}

